def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            if j % 2 == 0:
                score += (1/(j**2)) * (ratio ** j)
            else:
                score += (1/j) * (ratio ** (2*j))
        if capacity - item < 0.1 * capacity:
            score *= 2
        elif capacity - item < 0.2 * capacity:
            score *= 1.2
        else:
            score *= 0.8
        if capacity % 3 == 0:
            score -= 0.05 * (capacity % 5)
        elif capacity % 2 == 0:
            score -= 0.1
        else:
            score -= 0.02
        if ratio < 0.5 and capacity > 50:
            for k in range(1, 4):
                score += 0.1 * k / (capacity + k)
        if capacity > 100:
            score /= 1 + np.log1p(capacity)
        else:
            score *= 1 + np.sqrt(capacity) / 100
        priorities[i] = max(score, 0)
    return priorities
